import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void multiplePathsPicksShortest() {
        // 0→1→2→3=6; 0→2→3=7; 0→1→3=11 — answer is 6
        int[][] edges = {{0,1,3},{0,2,6},{1,2,2},{1,3,8},{2,3,1}};
        assertEquals(6, new Solution().shortestDag(4, edges, 0, 3));
    }

    @Test
    void negativeEdgeOnPath() {
        // 0→1 (+5), 1→2 (-3); total = 2
        int[][] edges = {{0,1,5},{1,2,-3}};
        assertEquals(2, new Solution().shortestDag(3, edges, 0, 2));
    }

    @Test
    void srcEqualsDst_returnsZero() {
        int[][] edges = {{0,1,4},{1,2,2}};
        assertEquals(0, new Solution().shortestDag(3, edges, 1, 1));
    }

    @Test
    void unreachable_returnsMinusOne() {
        // DAG: 0→1→2; node 3 is isolated
        int[][] edges = {{0,1,1},{1,2,1}};
        assertEquals(-1, new Solution().shortestDag(4, edges, 0, 3));
    }

    @Test
    void singleEdge_directPath() {
        int[][] edges = {{0,1,9}};
        assertEquals(9, new Solution().shortestDag(2, edges, 0, 1));
    }

    @Test
    void longerChainWithMix() {
        // 0→1(1)→2(1)→3(1)→4(1); shortest 0→4 = 4
        int[][] edges = {{0,1,1},{1,2,1},{2,3,1},{3,4,1}};
        assertEquals(4, new Solution().shortestDag(5, edges, 0, 4));
    }

    @Test
    void noEdges_singleNode() {
        int[][] edges = {};
        assertEquals(0, new Solution().shortestDag(1, edges, 0, 0));
    }
}
